import{_ as e,o,c as l,ag as i}from"./chunks/framework.CTpQozEL.js";const w=JSON.parse('{"title":"네트워크","description":"네트워크 허브: 게이트웨이 서피스, 페어링, 디스커버리, 보안","frontmatter":{"title":"네트워크","description":"네트워크 허브: 게이트웨이 서피스, 페어링, 디스커버리, 보안"},"headers":[],"relativePath":"network.md","filePath":"network.md","lastUpdated":null}'),r={name:"network.md"};function t(c,a,n,s,d,p){return o(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="네트워크-허브" tabindex="-1">네트워크 허브 <a class="header-anchor" href="#네트워크-허브" aria-label="Permalink to &quot;네트워크 허브&quot;">​</a></h1><p>이 허브는 OpenClaw가 localhost, LAN, 테일넷을 통해 기기를 연결, 페어링, 보안 설정하는 방법에 관한 핵심 문서를 연결합니다.</p><h2 id="핵심-모델" tabindex="-1">핵심 모델 <a class="header-anchor" href="#핵심-모델" aria-label="Permalink to &quot;핵심 모델&quot;">​</a></h2><p>대부분의 작업은 게이트웨이(<code>openclaw gateway</code>)를 통해 흐릅니다. 게이트웨이는 채널 연결과 WebSocket 컨트롤 플레인을 소유하는 단일 장기 실행 프로세스입니다.</p><ul><li><strong>루프백 우선</strong>: 게이트웨이 WS는 기본적으로 <code>ws://127.0.0.1:18789</code>입니다. 비루프백 바인드에는 유효한 게이트웨이 인증 경로가 필요합니다: 공유 비밀 토큰/패스워드 인증, 또는 올바르게 구성된 비루프백 <code>trusted-proxy</code> 배포.</li><li><strong>호스트당 하나의 게이트웨이</strong>를 권장합니다. 격리를 위해서는 격리된 프로파일과 포트로 여러 게이트웨이를 실행하십시오(<a href="/openclaw-docs-ko/gateway/multiple-gateways">다중 게이트웨이</a>).</li><li><strong>Canvas 호스트</strong>는 게이트웨이와 동일한 포트에서 제공됩니다(<code>/__openclaw__/canvas/</code>, <code>/__openclaw__/a2ui/</code>), 루프백 너머로 바인드될 때 게이트웨이 인증으로 보호됩니다.</li><li><strong>원격 접근</strong>은 일반적으로 SSH 터널 또는 Tailscale VPN입니다(<a href="/openclaw-docs-ko/gateway/remote">원격 접근</a>).</li></ul><p>주요 참조:</p><ul><li><a href="/openclaw-docs-ko/concepts/architecture">게이트웨이 아키텍처</a></li><li><a href="/openclaw-docs-ko/gateway/protocol">게이트웨이 프로토콜</a></li><li><a href="/openclaw-docs-ko/gateway">게이트웨이 런북</a></li><li><a href="/openclaw-docs-ko/web">웹 서피스 + 바인드 모드</a></li></ul><h2 id="페어링-신원" tabindex="-1">페어링 + 신원 <a class="header-anchor" href="#페어링-신원" aria-label="Permalink to &quot;페어링 + 신원&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/channels/pairing">페어링 개요 (DM + 노드)</a></li><li><a href="/openclaw-docs-ko/gateway/pairing">게이트웨이 소유 노드 페어링</a></li><li><a href="/openclaw-docs-ko/cli/devices">기기 CLI (페어링 + 토큰 순환)</a></li><li><a href="/openclaw-docs-ko/cli/pairing">페어링 CLI (DM 승인)</a></li></ul><p>로컬 신뢰:</p><ul><li>직접 로컬 루프백 연결은 동일 호스트 UX를 원활하게 유지하기 위해 페어링에 자동 승인될 수 있습니다.</li><li>OpenClaw에는 신뢰할 수 있는 공유 비밀 헬퍼 플로를 위한 좁은 백엔드/컨테이너 로컬 자체 연결 경로도 있습니다.</li><li>동일 호스트 테일넷 바인드를 포함한 테일넷 및 LAN 클라이언트는 여전히 명시적 페어링 승인이 필요합니다.</li></ul><h2 id="디스커버리-전송" tabindex="-1">디스커버리 + 전송 <a class="header-anchor" href="#디스커버리-전송" aria-label="Permalink to &quot;디스커버리 + 전송&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/gateway/discovery">디스커버리 &amp; 전송</a></li><li><a href="/openclaw-docs-ko/gateway/bonjour">Bonjour / mDNS</a></li><li><a href="/openclaw-docs-ko/gateway/remote">원격 접근 (SSH)</a></li><li><a href="/openclaw-docs-ko/gateway/tailscale">Tailscale</a></li></ul><h2 id="노드-전송" tabindex="-1">노드 + 전송 <a class="header-anchor" href="#노드-전송" aria-label="Permalink to &quot;노드 + 전송&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/nodes">노드 개요</a></li><li><a href="/openclaw-docs-ko/gateway/bridge-protocol">브리지 프로토콜 (레거시 노드, 역사적)</a></li><li><a href="/openclaw-docs-ko/platforms/ios">노드 런북: iOS</a></li><li><a href="/openclaw-docs-ko/platforms/android">노드 런북: Android</a></li></ul><h2 id="보안" tabindex="-1">보안 <a class="header-anchor" href="#보안" aria-label="Permalink to &quot;보안&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/gateway/security">보안 개요</a></li><li><a href="/openclaw-docs-ko/gateway/configuration">게이트웨이 구성 참조</a></li><li><a href="/openclaw-docs-ko/gateway/troubleshooting">문제 해결</a></li><li><a href="/openclaw-docs-ko/gateway/doctor">Doctor</a></li></ul>',17)])])}const u=e(r,[["render",t]]);export{w as __pageData,u as default};
